module float_multi (
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

reg [2:0] counter;
reg [23:0] a_mantissa, b_mantissa, z_mantissa;
reg [9:0] a_exponent, b_exponent, z_exponent;
reg a_sign, b_sign, z_sign;
reg [49:0] product;
reg guard_bit, round_bit, sticky;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        counter <= 0;
        a_mantissa <= 0;
        b_mantissa <= 0;
        z_mantissa <= 0;
        a_exponent <= 0;
        b_exponent <= 0;
        z_exponent <= 0;
        a_sign <= 0;
        b_sign <= 0;
        z_sign <= 0;
        product <= 0;
        guard_bit <= 0;
        round_bit <= 0;
        sticky <= 0;
        z <= 0;
    end else begin
        case (counter)
            0: begin 
                a_sign <= a[31];
                a_exponent <= a[30:23];
                a_mantissa <= {a[22:0], 1'b1};
                b_sign <= b[31];
                b_exponent <= b[30:23];
                b_mantissa <= {b[22:0], 1'b1};
            end
            1: begin 
                if ((a_exponent == 31 && a_mantissa != 0) || (b_exponent == 31 && b_mantissa != 0)) begin
                    z <= 32'hFFFFFFFF; 
                end else if ((a_exponent == 31 && a_mantissa == 0) || (b_exponent == 31 && b_mantissa == 0)) begin
                    z <= 32'h80000000; 
                end else begin
                    counter <= 2;
                end
            end
            2: begin 
                if (a_mantissa[23] == 0) begin
                    a_exponent <= a_exponent - 1;
                    a_mantissa <= {a_mantissa[22:0], 1'b1};
                end
                if (b_mantissa[23] == 0) begin
                    b_exponent <= b_exponent - 1;
                    b_mantissa <= {b_mantissa[22:0], 1'b1};
                end
                counter <= 3;
            end
            3: begin 
                product <= a_mantissa * b_mantissa;
                z_sign <= a_sign ^ b_sign;
                z_exponent <= a_exponent + b_exponent - 127;
                z_mantissa <= product[49:26];
                counter <= 4;
            end
            4: begin 
                guard_bit <= product[25];
                round_bit <= product[24];
                sticky <= |product[23:0];
                if (round_bit && (sticky || guard_bit)) begin
                    z_mantissa <= z_mantissa + 1;
                end
                if (z_mantissa[23]) begin
                    z_mantissa <= {z_mantissa[22:0], 1'b0};
                    z_exponent <= z_exponent + 1;
                end
                counter <= 5;
            end
            5: begin 
                z <= {z_sign, z_exponent, z_mantissa};
                counter <= 0;
            end
        endcase
    end
end

endmodule
